```class Solution {
public:
    string lastSubstring(string s) {
        int n = s.length();
        int maxIdx = n - 1;
        for (int i = n - 2; i >= 0; i--) {
            if (s[i] > s[maxIdx]) {
                maxIdx = i;
            }
        }
        return s.substr(maxIdx + 1, n - maxIdx - 1);
    }
};```

